import{_ as e,o as r,c as l,ag as t}from"./chunks/framework.f_9xDHrT.js";const u=JSON.parse('{"title":"出海垂钓","description":"如何用 MissFisher 进行海钓并查看信息。","frontmatter":{"title":"出海垂钓","description":"如何用 MissFisher 进行海钓并查看信息。"},"headers":[],"relativePath":"manual/scenarios/ocean.md","filePath":"manual/scenarios/ocean.md","lastUpdated":1778062636000}'),o={name:"manual/scenarios/ocean.md"};function i(n,a,s,h,c,p){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="出海垂钓" tabindex="-1">出海垂钓 <a class="header-anchor" href="#出海垂钓" aria-label="Permalink to &quot;出海垂钓&quot;">​</a></h1><blockquote><p>可完成渔分成就、收集蓝色稀有度鱼类、完成种类数量要求的奖励成就。</p></blockquote><ul><li><strong>相关设置项：</strong><br> 出海垂钓时自动丢弃。</li></ul><h2 id="前往入口" tabindex="-1">前往入口 <a class="header-anchor" href="#前往入口" aria-label="Permalink to &quot;前往入口&quot;">​</a></h2><ol><li>在主界面 - 主页切换海钓相关模式。</li><li>按住 Ctrl 对模式下拉按下右键 / 中键，可发起前往海钓入口的传送和寻路。</li></ol><h2 id="耐力模式" tabindex="-1">耐力模式 <a class="header-anchor" href="#耐力模式" aria-label="Permalink to &quot;耐力模式&quot;">​</a></h2><p>耐力模式是多轮次、全自动的模式，可在任务外启动，启动时会检查基本必要条件，例如需求的所有钓饵的携带情况和需求的最少背包空间等。如果不满足基本条件，将报告错误。</p><p>启动后，耐力模式能自动等候登船开放，并在可登记时按最佳策略选择航线、自动登船；<br> 进入任务后，会自行寻找可钓位置并启动对应模式。</p><p>在出海垂钓结束时，会在结算后自动退出副本，并等待下一次登记开放。</p><ul><li><strong>不带耐力前缀的模式：</strong><br> 单轮次的模式；<br> 只能在出海垂钓内启动，且不会在启动前进行基本必要条件检查。</li></ul><h2 id="冲分" tabindex="-1">冲分 <a class="header-anchor" href="#冲分" aria-label="Permalink to &quot;冲分&quot;">​</a></h2><p>冲分模式会尽可能获取更多渔分。<br> 在出海垂钓任务外启动耐力冲分模式，可自动检查钓饵和背包空间，并在登船时选择最佳冲分航线。</p><ul><li><p><strong>航班标签：</strong><br> 有下列标签表示在该航班更有可能获得高分：<br> 高分、高分II</p></li><li><p><strong>相关设置项：</strong><br> 触幻提示播报频道。</p></li></ul><h2 id="蓝鱼" tabindex="-1">蓝鱼 <a class="header-anchor" href="#蓝鱼" aria-label="Permalink to &quot;蓝鱼&quot;">​</a></h2><p>蓝鱼模式会尽可能钓当前航线的目标蓝色稀有度鱼类。<br> 在出海垂钓任务外启动耐力蓝鱼模式，可自动检查钓饵和背包空间，并在登船时按所需目标选择航线。</p><ul><li><strong>相关设置项：</strong><br> 蓝鱼目标；<br> 无目标时不跳过登船。</li></ul><h2 id="种类" tabindex="-1">种类 <a class="header-anchor" href="#种类" aria-label="Permalink to &quot;种类&quot;">​</a></h2><blockquote><p>在社区，此类需求可能被称为：成就、称号</p></blockquote><p>种类模式会尽可能钓当前航线的符合目标种类的鱼类。种类模式没有耐力模式。</p><p>大部分种类加成计入整个小队的钓获数量，且需要大量数量，因此必须组队完成。</p><p>当前航班适合完成的种类标签和计数类型会在下列位置显示：</p><ul><li>模式下拉菜单中的种类模式项的悬停提示；</li><li>选择好种类模式后的模式下拉按钮；</li><li>选择好种类模式后的启动按钮；</li><li>另外也可在航线页查看。</li></ul><h2 id="非幻海流钓场的稀有鱼类" tabindex="-1">非幻海流钓场的稀有鱼类 <a class="header-anchor" href="#非幻海流钓场的稀有鱼类" aria-label="Permalink to &quot;非幻海流钓场的稀有鱼类&quot;">​</a></h2><p>见<a href="./fish#出海垂钓中的稀有鱼类">出海垂钓中的稀有鱼类</a>。</p><h2 id="航线信息" tabindex="-1">航线信息 <a class="header-anchor" href="#航线信息" aria-label="Permalink to &quot;航线信息&quot;">​</a></h2><p>在主界面 - 航线页可以筛选、搜索和查看易懂的出海垂钓航班信息。</p>',26)])])}const b=e(o,[["render",i]]);export{u as __pageData,b as default};
